There is a miscompilation issue report in LoopUnroll: 

```console
% clang-tk -v
clang version 16.0.0 (https://github.com/llvm/llvm-project.git 0c1a3da8ea1f0e024ebfd85c7532926f26c6bde5)
Target: x86_64-unknown-linux-gnu
Thread model: posix
InstalledDir: /zdata/shaoli/compilers/ccbuilder-compilers
Found candidate GCC installation: /usr/lib/gcc/x86_64-linux-gnu/11
Found candidate GCC installation: /usr/lib/gcc/x86_64-linux-gnu/9
Selected GCC installation: /usr/lib/gcc/x86_64-linux-gnu/11
Candidate multilib: .;@m64
Selected multilib: .;@m64
%
% clang-tk -w -O0 a.c && ./a.out
2
% clang-tk -w -O3 a.c && ./a.out
9
% cat a.c
void printf();
long a;
int b, d, e;
int *c;
void f(int *g) { *g = b; }
char h() {
  long *i = &a;
  for (;;) {
    int j = 0;
    for (;; a++) {
      b = 2;
      for (; b <= 8; b++) {
        c = &j;
        if (j)
          break;
      }
      if (j)
        break;
      j = 1;
    }
    e = 3;
    for (; e <= 8; e++) {
      int k;
      d = 3;
      for (; d <= 8; d++) {
        *i = k;
        f(&k);
      }
      if (a)
        return 0;
    }
  }
}
int main() {
  h();
  printf("%d\n", a);
}
%
```

Compiler explorer: https://godbolt.org/z/WTce7z7Md

`opt-bisect-limit` indicates the issue maybe in `IndVarSimplifyPass`

The maintainers proposed the following patch to fix the issue:

commit e302fa89aa45afceedb711a264cfc486395aca17
Author: Florian Hahn <flo@fhahn.com>
Date:   Tue Oct 18 15:12:23 2022 +0100

    [LoopUnroll] Forget exit values when making changes.

    When unrolling, the exit values in LCSSA phis will get updated.
    Invalidate cached SCEV values for those phis in case SCEV looked through
    a exit phi.

    Fixes #58340.

diff --git a/llvm/lib/Transforms/Utils/LoopUnroll.cpp b/llvm/lib/Transforms/Utils/LoopUnroll.cpp
index 6d6c3db034ca..fd874db6981b 100644
--- a/llvm/lib/Transforms/Utils/LoopUnroll.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUnroll.cpp
@@ -578,6 +578,7 @@ LoopUnrollResult llvm::UnrollLoop(Loop *L, UnrollLoopOptions ULO, LoopInfo *LI,
           if (It != LastValueMap.end())
             Incoming = It->second;
           PHI.addIncoming(Incoming, New);
+          SE->forgetValue(&PHI);
         }
       }
